INSERT OR IGNORE INTO statute_sections VALUES(2938,12,'251','Amendments of Act 54 of 2002','The Securitisation and Reconstruction of Financial Assets and Enforcement of Security Interest Act, 2002 shall be amended in the manner specified in the Seventh Schedule.');
